class Solution:
    def maximumsSplicedArray(self, nums1, nums2):
        n = len(nums1)
        s1 = sum(nums1)
        s2 = sum(nums2)
        best = max(s1, s2)
        for left in range(n):
            d1 = s1
            d2 = s2
            for right in range(left, n):
                d1 += nums2[right] - nums1[right]
                d2 += nums1[right] - nums2[right]
                if d1 > best:
                    best = d1
                if d2 > best:
                    best = d2
        return best

