class Solution:
    def maximumsSplicedArray(self, nums1, nums2):
        s1 = sum(nums1)
        s2 = sum(nums2)
        def best_gain(a, b):
            cur = 0
            mx = 0
            for x, y in zip(a, b):
                cur = max(0, cur + (y - x))
                mx = max(mx, cur)
            return mx
        g1 = best_gain(nums1, nums2)
        g2 = best_gain(nums2, nums1)
        return max(s1 + g1, s2 + g2)

