var maximumsSplicedArray = function(nums1, nums2) {
    const sum = arr => arr.reduce((a, b) => a + b, 0);
    const s1 = sum(nums1);
    const s2 = sum(nums2);
    const bestGain = (a, b) => {
        let cur = 0, mx = 0;
        for (let i = 0; i < a.length; i++) {
            cur = Math.max(0, cur + (b[i] - a[i]));
            mx = Math.max(mx, cur);
        }
        return mx;
    };
    const g1 = bestGain(nums1, nums2);
    const g2 = bestGain(nums2, nums1);
    return Math.max(s1 + g1, s2 + g2);
};
